import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"版本日志: 功能更新 | OpenSkills","description":"查看 OpenSkills 版本变更历史，了解 update 命令、符号链接、私有仓库等新功能，以及路径遍历防护等重要改进和问题修复。","frontmatter":{"title":"版本日志: 功能更新 | OpenSkills","sidebarTitle":"看看新功能","subtitle":"版本日志: 功能更新 | OpenSkills","description":"查看 OpenSkills 版本变更历史，了解 update 命令、符号链接、私有仓库等新功能，以及路径遍历防护等重要改进和问题修复。","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"zh/numman-ali/openskills/changelog/changelog/index.md","filePath":"zh/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"zh/numman-ali/openskills/changelog/changelog/index.md"};function t(n,l,s,d,h,c){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>本页面记录 OpenSkills 的版本变更历史，帮助你了解每个版本的新功能、改进和问题修复。</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - 从记录的来源刷新已安装技能（默认：全部刷新）</li><li><strong>源元数据跟踪</strong> - 安装时现在记录来源信息，用于可靠地更新技能</li></ul><h3 id="改进" tabindex="-1">改进 <a class="header-anchor" href="#改进" aria-label="Permalink to &quot;改进&quot;">​</a></h3><ul><li><strong>多技能读取</strong> - <code>openskills read</code> 命令现在支持逗号分隔的技能名列表</li><li><strong>生成使用说明</strong> - 优化了 shell 环境下的 read 命令调用提示</li><li><strong>README</strong> - 添加了更新指南和人工使用提示</li></ul><h3 id="问题修复" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复" aria-label="Permalink to &quot;问题修复&quot;">​</a></h3><ul><li><strong>更新体验优化</strong> - 跳过没有源元数据的技能，并列出这些技能提示重新安装</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="改进-1" tabindex="-1">改进 <a class="header-anchor" href="#改进-1" aria-label="Permalink to &quot;改进&quot;">​</a></h3><ul><li><strong>README</strong> - 明确项目本地默认安装方式，移除冗余的 sync 提示</li><li><strong>安装消息</strong> - 安装器现在明确区分项目本地默认安装与 <code>--global</code> 选项</li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="改进-2" tabindex="-1">改进 <a class="header-anchor" href="#改进-2" aria-label="Permalink to &quot;改进&quot;">​</a></h3><ul><li><strong>文档与 AGENTS.md 指引</strong> - 所有命令示例和生成的使用说明统一使用 <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="问题修复-1" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复-1" aria-label="Permalink to &quot;问题修复&quot;">​</a></h3><ul><li><strong>Windows 安装</strong> - 修复了 Windows 系统上的路径验证问题（&quot;Security error: Installation path outside target directory&quot;）</li><li><strong>CLI 版本</strong> - <code>npx openskills --version</code> 现在正确读取 package.json 中的版本号</li><li><strong>根目录 SKILL.md</strong> - 修复了 SKILL.md 在仓库根目录的单技能仓库安装问题</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="新增功能-1" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-1" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><p><strong>符号链接支持</strong> - 技能现在可以通过符号链接安装到技能目录 (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>支持通过从克隆仓库创建符号链接来实现基于 git 的技能更新</li><li>支持本地技能开发工作流</li><li>损坏的符号链接会被优雅地跳过</li></ul></li><li><p><strong>可配置输出路径</strong> - sync 命令新增 <code>--output</code> / <code>-o</code> 选项 (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>可同步到任意 <code>.md</code> 文件（如 <code>.ruler/AGENTS.md</code>）</li><li>如果文件不存在，自动创建文件并添加标题</li><li>如果需要，自动创建嵌套目录</li></ul></li><li><p><strong>本地路径安装</strong> - 支持从本地目录安装技能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>支持绝对路径（<code>/path/to/skill</code>）</li><li>支持相对路径（<code>./skill</code>、<code>../skill</code>）</li><li>支持波浪号扩展（<code>~/my-skills/skill</code>）</li></ul></li><li><p><strong>私有 git 仓库支持</strong> - 支持从私有仓库安装技能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URLs（<code>git@github.com:org/private-skills.git</code>）</li><li>带认证的 HTTPS URLs</li><li>自动使用系统 SSH 密钥</li></ul></li><li><p><strong>全面的测试套件</strong> - 跨 6 个测试文件的 88 个测试</p><ul><li>符号链接检测、YAML 解析的单元测试</li><li>install、sync 命令的集成测试</li><li>完整 CLI 工作流的端到端测试</li></ul></li></ul><h3 id="改进-3" tabindex="-1">改进 <a class="header-anchor" href="#改进-3" aria-label="Permalink to &quot;改进&quot;">​</a></h3><ul><li><p><strong><code>--yes</code> 标志现在跳过所有提示</strong> - 完全非交互模式，适用于 CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>覆盖现有技能时不提示</li><li>跳过提示时显示 <code>Overwriting: &lt;skill-name&gt;</code> 消息</li><li>所有命令现在都可以在无头环境中运行</li></ul></li><li><p><strong>CI 工作流重排</strong> - 构建步骤现在在测试之前运行</p><ul><li>确保 <code>dist/cli.js</code> 存在，用于端到端测试</li></ul></li></ul><h3 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h3><ul><li><strong>路径遍历防护</strong> - 验证安装路径保持在目标目录内</li><li><strong>符号链接解引用</strong> - <code>cpSync</code> 使用 <code>dereference: true</code> 安全地复制符号链接目标</li><li><strong>非贪婪 YAML 正则</strong> - 防止 frontmatter 解析中潜在的 ReDoS 攻击</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="问题修复-2" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复-2" aria-label="Permalink to &quot;问题修复&quot;">​</a></h3><ul><li>README 文档清理 - 移除了重复部分和错误的标志</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="新增功能-2" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-2" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><code>--universal</code> 标志，将技能安装到 <code>.agent/skills/</code> 而非 <code>.claude/skills/</code><ul><li>适用于多代理环境（Claude Code + Cursor/Windsurf/Aider）</li><li>避免与 Claude Code 原生市场插件冲突</li></ul></li></ul><h3 id="改进-4" tabindex="-1">改进 <a class="header-anchor" href="#改进-4" aria-label="Permalink to &quot;改进&quot;">​</a></h3><ul><li>项目本地安装现在是默认选项（之前是全局安装）</li><li>技能默认安装到 <code>./.claude/skills/</code></li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="新增功能-3" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-3" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li>全面的单页 README，包含技术深度解析</li><li>与 Claude Code 的并列对比</li></ul><h3 id="问题修复-3" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复-3" aria-label="Permalink to &quot;问题修复&quot;">​</a></h3><ul><li>位置标签现在根据安装位置正确显示 <code>project</code> 或 <code>global</code></li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="新增功能-4" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-4" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li>初始发布</li><li><code>npx openskills install &lt;source&gt;</code> - 从 GitHub 仓库安装技能</li><li><code>npx openskills sync</code> - 为 AGENTS.md 生成 <code>&lt;available_skills&gt;</code> XML</li><li><code>npx openskills list</code> - 显示已安装的技能</li><li><code>npx openskills read &lt;name&gt;</code> - 为代理加载技能内容</li><li><code>npx openskills manage</code> - 交互式技能删除</li><li><code>npx openskills remove &lt;name&gt;</code> - 删除指定技能</li><li>所有命令的交互式 TUI 界面</li><li>支持 Anthropic 的 SKILL.md 格式</li><li>渐进式披露（按需加载技能）</li><li>打包资源支持（references/、scripts/、assets/）</li></ul><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th></tr></thead><tbody><tr><td>更新日志原文</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=e(r,[["render",t]]);export{g as __pageData,m as default};
